/// AI Intelligence Module — Insights, document processing, and search embeddings
///
/// # Tables
/// | Table | Description |
/// |-------|-------------|
/// | **AiInsight** | Business intelligence insights generated by AI agents |
/// | **AiDocumentProcessingJob** | OCR / extraction / classification jobs |
/// | **SearchEmbedding** | Vector embeddings for semantic search |
use spacetimedb::{reducer, Identity, ReducerContext, SpacetimeType, Table, Timestamp};

use crate::core::queue::{queue_job, QueueJob};
use crate::helpers::{check_permission, write_audit_log_v2, AuditLogParams};
use crate::types::{InsightSeverity, JobStatus};

// ============================================================================
// PARAMS TYPES
// ============================================================================

/// Params for creating an AI insight.
/// Scope: `company_id` is a flat reducer param (not in this struct).
#[derive(SpacetimeType, Clone, Debug)]
pub struct CreateAiInsightParams {
    pub severity: InsightSeverity,
    pub title: String,
    pub description: String,
    pub recommendations: Vec<String>,
    pub related_model: String,
    pub confidence: f64,
    pub tags: Vec<String>,
    pub related_id: Option<u64>,
    pub generated_by: Option<u64>,
    pub impact_score: Option<f64>,
    pub priority: Option<u8>,
    pub metadata: Option<String>,
}

/// Params for creating a document processing job.
/// Scope: `company_id` is a flat reducer param (not in this struct).
#[derive(SpacetimeType, Clone, Debug)]
pub struct CreateDocumentProcessingJobParams {
    pub document_type: String,
    pub job_type: String,
    pub ai_agent_id: Option<u64>,
    pub input_data: Option<String>,
    pub metadata: Option<String>,
}

/// Params for completing a document processing job.
/// Scope: `company_id` + `job_id` are flat reducer params.
/// `status` is computed: Failed if `error_message` is Some, else Completed.
#[derive(SpacetimeType, Clone, Debug)]
pub struct CompleteDocumentProcessingJobParams {
    pub extracted_data: Option<String>,
    pub confidence_score: Option<f64>,
    pub model_used: Option<String>,
    pub tokens_used: Option<u32>,
    pub cost: Option<f64>,
    pub error_message: Option<String>,
}

/// Params for upserting a search embedding.
/// Scope: `company_id` is a flat reducer param (not in this struct).
#[derive(SpacetimeType, Clone, Debug)]
pub struct UpsertSearchEmbeddingParams {
    pub content_type: String,
    pub content_id: u64,
    pub text: String,
    pub embedding: Vec<f32>,
    pub embedding_hash: Option<String>,
    pub metadata: Option<String>,
}

// ============================================================================
// TABLES
// ============================================================================

/// AiInsight — A business intelligence finding generated by an AI agent
#[derive(Clone)]
#[spacetimedb::table(
    accessor = ai_insight,
    public,
    index(accessor = insight_by_model, btree(columns = [related_model])),
    index(accessor = insight_by_company, btree(columns = [company_id]))
)]
pub struct AiInsight {
    #[primary_key]
    #[auto_inc]
    pub id: u64,

    pub severity: InsightSeverity,
    pub title: String,
    pub description: String,
    pub recommendations: Vec<String>,
    pub related_model: String, // e.g., "sale_order", "inventory"
    pub related_id: Option<u64>,
    pub confidence: f64, // 0.0–1.0
    pub generated_at: Timestamp,
    pub generated_by: Option<u64>, // AI Agent ID
    pub is_acknowledged: bool,
    pub acknowledged_by: Option<Identity>,
    pub acknowledged_at: Option<Timestamp>,
    pub dismissed: bool,
    pub dismissed_by: Option<Identity>,
    pub dismissed_at: Option<Timestamp>,
    pub action_taken: Option<String>,
    pub impact_score: Option<f64>,
    pub priority: Option<u8>,
    pub tags: Vec<String>,
    pub company_id: Option<u64>,
    pub create_uid: Identity,
    pub create_date: Timestamp,
    pub write_uid: Identity,
    pub write_date: Timestamp,
    pub metadata: Option<String>,
}

/// AiDocumentProcessingJob — AI-powered document OCR, extraction, or classification
#[derive(Clone)]
#[spacetimedb::table(
    accessor = ai_document_processing_job,
    public,
    index(name = "by_status", accessor = doc_job_by_status, btree(columns = [status])),
    index(accessor = doc_job_by_company, btree(columns = [company_id]))
)]
pub struct AiDocumentProcessingJob {
    #[primary_key]
    #[auto_inc]
    pub id: u64,

    pub document_type: String, // Invoice, Receipt, Contract, etc.
    pub job_type: String,      // OCR, Extraction, Classification, Analysis
    pub status: JobStatus,
    pub ai_agent_id: Option<u64>,
    pub model_used: Option<String>,
    pub input_data: Option<String>, // JSON — source document reference
    pub extracted_data: Option<String>, // JSON — extracted fields
    pub confidence_score: Option<f64>,
    pub error_message: Option<String>,
    pub processing_started_at: Option<Timestamp>,
    pub processing_completed_at: Option<Timestamp>,
    pub tokens_used: Option<u32>,
    pub cost: Option<f64>,
    pub reviewed_by: Option<Identity>,
    pub reviewed_at: Option<Timestamp>,
    pub is_approved: bool,
    pub company_id: Option<u64>,
    pub create_uid: Identity,
    pub create_date: Timestamp,
    pub write_uid: Identity,
    pub write_date: Timestamp,
    pub metadata: Option<String>,
}

/// SearchEmbedding — Vector embedding for a piece of content (semantic search)
#[derive(Clone)]
#[spacetimedb::table(
    accessor = search_embedding,
    public,
    index(name = "by_content", accessor = embedding_by_content, btree(columns = [content_type])),
    index(accessor = embedding_by_company, btree(columns = [company_id])),
    index(name = "by_sync_status", accessor = embedding_by_sync_status, btree(columns = [sync_status]))
)]
pub struct SearchEmbedding {
    #[primary_key]
    #[auto_inc]
    pub id: u64,

    pub content_type: String, // product, contact, document, article, etc.
    pub content_id: u64,
    pub text: String,                   // Original text that was embedded
    pub embedding: Vec<f32>,            // Vector embedding values (backup copy)
    pub embedding_hash: Option<String>, // Hash of text for change detection

    // Qdrant sync tracking
    pub sync_status: String, // "pending" | "synced" | "failed" | "deleted"
    pub vector_db_id: Option<String>, // Qdrant point ID (stringified STDB id)
    pub embedding_model: Option<String>, // e.g. "voyage-3", "text-embedding-3-small"
    pub embedding_dim: Option<u32>, // e.g. 1024, 1536 — for model migration tracking
    pub last_synced_at: Option<Timestamp>,
    pub sync_error: Option<String>, // Last sync error message

    pub company_id: Option<u64>,
    pub create_uid: Identity,
    pub create_date: Timestamp,
    pub write_uid: Identity,
    pub write_date: Timestamp,
    pub metadata: Option<String>,
}

