/// Create an AI insight (typically called by an AI integration process)
#[reducer]
pub fn create_ai_insight(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    params: CreateAiInsightParams,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_insight", "create")?;

    if params.confidence < 0.0 || params.confidence > 1.0 {
        return Err("Confidence must be between 0.0 and 1.0".to_string());
    }

    let insight = ctx.db.ai_insight().insert(AiInsight {
        id: 0,
        severity: params.severity,
        title: params.title,
        description: params.description,
        recommendations: params.recommendations,
        related_model: params.related_model,
        related_id: params.related_id,
        confidence: params.confidence,
        // System-managed: set to creation time
        generated_at: ctx.timestamp,
        generated_by: params.generated_by,
        // System-managed: starts unacknowledged and undismissed
        is_acknowledged: false,
        acknowledged_by: None,
        acknowledged_at: None,
        dismissed: false,
        dismissed_by: None,
        dismissed_at: None,
        action_taken: None,
        impact_score: params.impact_score,
        priority: params.priority,
        tags: params.tags,
        company_id,
        create_uid: ctx.sender(),
        create_date: ctx.timestamp,
        write_uid: ctx.sender(),
        write_date: ctx.timestamp,
        metadata: params.metadata,
    });

    write_audit_log_v2(
        ctx,
        cid,
        AuditLogParams {
            company_id,
            table_name: "ai_insight",
            record_id: insight.id,
            action: "create",
            old_values: None,
            new_values: None,
            changed_fields: vec!["created".to_string()],
            metadata: None,
        },
    );

    log::info!(
        "AI insight created: id={}, severity={:?}",
        insight.id,
        insight.severity
    );
    Ok(())
}

/// Acknowledge an AI insight
#[reducer]
pub fn acknowledge_insight(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    insight_id: u64,
    action_taken: Option<String>,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_insight", "write")?;

    let insight = ctx
        .db
        .ai_insight()
        .id()
        .find(&insight_id)
        .ok_or("Insight not found")?;

    if insight.is_acknowledged {
        return Ok(()); // Idempotent
    }

    ctx.db.ai_insight().id().update(AiInsight {
        is_acknowledged: true,
        acknowledged_by: Some(ctx.sender()),
        acknowledged_at: Some(ctx.timestamp),
        action_taken,
        write_uid: ctx.sender(),
        write_date: ctx.timestamp,
        ..insight
    });

    write_audit_log_v2(
        ctx,
        cid,
        AuditLogParams {
            company_id,
            table_name: "ai_insight",
            record_id: insight_id,
            action: "write",
            old_values: None,
            new_values: None,
            changed_fields: vec!["acknowledged".to_string()],
            metadata: None,
        },
    );

    log::info!("AI insight acknowledged: id={}", insight_id);
    Ok(())
}

/// Dismiss an AI insight
#[reducer]
pub fn dismiss_insight(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    insight_id: u64,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_insight", "write")?;

    let insight = ctx
        .db
        .ai_insight()
        .id()
        .find(&insight_id)
        .ok_or("Insight not found")?;

    if insight.dismissed {
        return Ok(()); // Idempotent
    }

    ctx.db.ai_insight().id().update(AiInsight {
        dismissed: true,
        dismissed_by: Some(ctx.sender()),
        dismissed_at: Some(ctx.timestamp),
        write_uid: ctx.sender(),
        write_date: ctx.timestamp,
        ..insight
    });

    write_audit_log_v2(
        ctx,
        cid,
        AuditLogParams {
            company_id,
            table_name: "ai_insight",
            record_id: insight_id,
            action: "write",
            old_values: None,
            new_values: None,
            changed_fields: vec!["dismissed".to_string()],
            metadata: None,
        },
    );

    log::info!("AI insight dismissed: id={}", insight_id);
    Ok(())
}

/// Submit a new document processing job
#[reducer]
pub fn create_document_processing_job(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    params: CreateDocumentProcessingJobParams,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_document_processing_job", "create")?;

    let job = ctx
        .db
        .ai_document_processing_job()
        .insert(AiDocumentProcessingJob {
            id: 0,
            document_type: params.document_type,
            job_type: params.job_type,
            // System-managed: new jobs always start as Pending
            status: JobStatus::Pending,
            ai_agent_id: params.ai_agent_id,
            input_data: params.input_data,
            // System-managed: populated by complete_document_processing_job
            model_used: None,
            extracted_data: None,
            confidence_score: None,
            error_message: None,
            processing_started_at: None,
            processing_completed_at: None,
            tokens_used: None,
            cost: None,
            reviewed_by: None,
            reviewed_at: None,
            // System-managed: set to true only via approve_document_processing_job
            is_approved: false,
            company_id,
            create_uid: ctx.sender(),
            create_date: ctx.timestamp,
            write_uid: ctx.sender(),
            write_date: ctx.timestamp,
            metadata: params.metadata,
        });

    write_audit_log_v2(
        ctx,
        cid,
        AuditLogParams {
            company_id,
            table_name: "ai_document_processing_job",
            record_id: job.id,
            action: "create",
            old_values: None,
            new_values: None,
            changed_fields: vec!["submitted".to_string()],
            metadata: None,
        },
    );

    log::info!(
        "Document processing job created: id={}, type={}/{}",
        job.id,
        job.document_type,
        job.job_type
    );
    Ok(())
}

/// Update the result of a document processing job
#[reducer]
pub fn complete_document_processing_job(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    job_id: u64,
    params: CompleteDocumentProcessingJobParams,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_document_processing_job", "write")?;

    let job = ctx
        .db
        .ai_document_processing_job()
        .id()
        .find(&job_id)
        .ok_or("Processing job not found")?;

    // status is computed: Failed if error_message present, else Completed
    let status = if params.error_message.is_some() {
        JobStatus::Failed
    } else {
        JobStatus::Completed
    };

    ctx.db
        .ai_document_processing_job()
        .id()
        .update(AiDocumentProcessingJob {
            status,
            extracted_data: params.extracted_data,
            confidence_score: params.confidence_score,
            model_used: params.model_used,
            tokens_used: params.tokens_used,
            cost: params.cost,
            error_message: params.error_message,
            processing_completed_at: Some(ctx.timestamp),
            write_uid: ctx.sender(),
            write_date: ctx.timestamp,
            ..job
        });

    write_audit_log_v2(
        ctx,
        cid,
        AuditLogParams {
            company_id,
            table_name: "ai_document_processing_job",
            record_id: job_id,
            action: "write",
            old_values: None,
            new_values: None,
            changed_fields: vec!["completed".to_string()],
            metadata: None,
        },
    );

    log::info!("Document processing job completed: id={}", job_id);
    Ok(())
}

/// Approve extracted data from a processing job
#[reducer]
pub fn approve_document_processing_job(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    job_id: u64,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_document_processing_job", "write")?;

    let job = ctx
        .db
        .ai_document_processing_job()
        .id()
        .find(&job_id)
        .ok_or("Processing job not found")?;

    if job.status != JobStatus::Completed {
        return Err("Job must be completed before approval".to_string());
    }

    ctx.db
        .ai_document_processing_job()
        .id()
        .update(AiDocumentProcessingJob {
            is_approved: true,
            reviewed_by: Some(ctx.sender()),
            reviewed_at: Some(ctx.timestamp),
            write_uid: ctx.sender(),
            write_date: ctx.timestamp,
            ..job
        });

    write_audit_log_v2(
        ctx,
        cid,
        AuditLogParams {
            company_id,
            table_name: "ai_document_processing_job",
            record_id: job_id,
            action: "write",
            old_values: None,
            new_values: None,
            changed_fields: vec!["approved".to_string()],
            metadata: None,
        },
    );

    log::info!("Document processing job approved: id={}", job_id);
    Ok(())
}

/// Upsert a search embedding for a piece of content
#[reducer]
pub fn upsert_search_embedding(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    params: UpsertSearchEmbeddingParams,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "search_embedding", "create")?;

    // Check if an embedding already exists for this content
    let existing: Option<SearchEmbedding> = ctx
        .db
        .search_embedding()
        .embedding_by_content()
        .filter(&params.content_type)
        .find(|e| e.content_id == params.content_id && e.company_id == company_id);

    if let Some(existing) = existing {
        // Reset sync_status to "pending" so the gateway re-indexes the updated content
        ctx.db.search_embedding().id().update(SearchEmbedding {
            text: params.text,
            embedding: params.embedding,
            embedding_hash: params.embedding_hash,
            sync_status: "pending".to_string(),
            last_synced_at: None,
            sync_error: None,
            write_uid: ctx.sender(),
            write_date: ctx.timestamp,
            ..existing
        });
        log::info!(
            "Search embedding updated: content_type={}, content_id={}",
            params.content_type,
            params.content_id
        );
    } else {
        ctx.db.search_embedding().insert(SearchEmbedding {
            id: 0,
            content_type: params.content_type.clone(),
            content_id: params.content_id,
            text: params.text,
            embedding: params.embedding,
            embedding_hash: params.embedding_hash,
            sync_status: "pending".to_string(),
            vector_db_id: None,
            embedding_model: None,
            embedding_dim: None,
            last_synced_at: None,
            sync_error: None,
            company_id,
            create_uid: ctx.sender(),
            create_date: ctx.timestamp,
            write_uid: ctx.sender(),
            write_date: ctx.timestamp,
            metadata: params.metadata,
        });
        log::info!(
            "Search embedding created: content_type={}, content_id={}",
            params.content_type,
            params.content_id
        );
    }

    Ok(())
}

/// Called by the AI Gateway after a vector has been successfully upserted into Qdrant.
/// Updates sync metadata so clients and workers can track indexing state.
#[reducer]
pub fn mark_embedding_synced(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    embedding_id: u64,
    model: String,
    dim: u32,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "search_embedding", "write")?;

    let existing = ctx
        .db
        .search_embedding()
        .id()
        .find(&embedding_id)
        .ok_or("Embedding not found")?;

    ctx.db.search_embedding().id().update(SearchEmbedding {
        sync_status: "synced".to_string(),
        vector_db_id: Some(embedding_id.to_string()),
        embedding_model: Some(model),
        embedding_dim: Some(dim),
        last_synced_at: Some(ctx.timestamp),
        sync_error: None,
        write_uid: ctx.sender(),
        write_date: ctx.timestamp,
        ..existing
    });

    log::info!("Search embedding synced to vector DB: id={}", embedding_id);
    Ok(())
}

/// Soft-delete a search embedding (marks as "deleted" so the AI Gateway removes it from Qdrant).
/// Preserves the row for audit trail.
#[reducer]
pub fn delete_search_embedding(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    content_type: String,
    content_id: u64,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "search_embedding", "delete")?;

    let existing = ctx
        .db
        .search_embedding()
        .embedding_by_content()
        .filter(&content_type)
        .find(|e| e.content_id == content_id && e.company_id == company_id)
        .ok_or("Embedding not found for this content")?;

    ctx.db.search_embedding().id().update(SearchEmbedding {
        sync_status: "deleted".to_string(),
        write_uid: ctx.sender(),
        write_date: ctx.timestamp,
        ..existing
    });

    log::info!(
        "Search embedding marked for deletion: content_type={}, content_id={}",
        content_type,
        content_id
    );
    Ok(())
}

/// Enqueue an embedding job for the AI Gateway worker to process.
/// Call this after creating or updating any ERP record that should be searchable.
/// The gateway polls the "embedding" queue, generates the vector, and calls mark_embedding_synced.
#[reducer]
pub fn request_embedding_job(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    content_type: String,
    content_id: u64,
    text: String,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "search_embedding", "create")?;

    let payload = format!(
        r#"{{"company_id":{},"content_type":"{}","content_id":{},"text":{}}}"#,
        cid,
        content_type,
        content_id,
        serde_json_escape(&text)
    );

    ctx.db.queue_job().insert(QueueJob {
        id: 0,
        organization_id: cid,
        queue_name: "embedding".to_string(),
        job_type: "embed_content".to_string(),
        payload,
        priority: 5,
        attempts: 0,
        max_attempts: 3,
        status: JobStatus::Pending,
        scheduled_at: None,
        started_at: None,
        completed_at: None,
        error_message: None,
        created_by: ctx.sender(),
        created_at: ctx.timestamp,
        metadata: None,
    });

    log::info!(
        "Embedding job queued: content_type={}, content_id={}",
        content_type,
        content_id
    );
    Ok(())
}

/// Minimal JSON string escaping for embedding payloads (avoids pulling in serde_json).
fn serde_json_escape(s: &str) -> String {
    let mut out = String::with_capacity(s.len() + 2);
    out.push('"');
    for c in s.chars() {
        match c {
            '"' => out.push_str("\\\""),
            '\\' => out.push_str("\\\\"),
            '\n' => out.push_str("\\n"),
            '\r' => out.push_str("\\r"),
            '\t' => out.push_str("\\t"),
            c => out.push(c),
        }
    }
    out.push('"');
    out
}
